def verify_password(username, password):
    user = USERS.get(username)
    return bool(user and user["password"] == password)

def verify_otp(username, otp):
    user = USERS.get(username)
    return bool(user and user["otp_secret"] == otp)

def issue_api_token(username):
    token = secrets.token_urlsafe(32)
    API_TOKENS[token] = {
        "username": username,
        "issued_at": datetime.utcnow(),
        "expires_at": datetime.utcnow() + timedelta(hours=12),
    }
    return token

def is_api_token_valid(token):
    data = API_TOKENS.get(token)
    if not data:
        return False
    if data["expires_at"] < datetime.utcnow():
        API_TOKENS.pop(token, None)
        return False
    return True

def login_required(view):
    @wraps(view)
    def wrapped(*args, **kwargs):
        if not session.get("authenticated"):
            return redirect(url_for("login"))
        return view(*args, **kwargs)
    return wrapped

def api_token_required(view):
    @wraps(view)
    def wrapped(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or invalid Authorization header"}), 401
        token = auth_header.split(" ", 1)[1].strip()
        if not is_api_token_valid(token):
            return jsonify({"error": "Invalid or expired token"}), 401
        request.api_user = API_TOKENS[token]["username"]
        return view(*args, **kwargs)
    return wrapped

@app.route("/")
@login_required
def home():
    return render_template_string(HOME_TEMPLATE, user=session.get("username"))

@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        return render_template_string(LOGIN_TEMPLATE, error=None)

    username = request.form.get("username", "").strip()
    password = request.form.get("password", "")

    if not verify_password(username, password):
        return render_template_string(LOGIN_TEMPLATE, error="Invalid username or password"), 401

    user = USERS[username]
    session.clear()

    if user["mfa_enabled"]:
        session["pre_auth_user"] = username
        session["mfa_required"] = True
        return redirect(url_for("mfa_verify"))

    session["authenticated"] = True
    session["username"] = username
    session["mfa_completed"] = False
    return redirect(url_for("home"))

@app.route("/mfa", methods=["GET", "POST"])
def mfa_verify():
    if not session.get("mfa_required") or not session.get("pre_auth_user"):
        return redirect(url_for("login"))

    if request.method == "GET":
        return render_template_string(OTP_TEMPLATE, error=None)

    otp = request.form.get("otp", "").strip()
    username = session.get("pre_auth_user")

    if not verify_otp(username, otp):
        return render_template_string(OTP_TEMPLATE, error="Invalid OTP"), 401

    session.clear()
    session["authenticated"] = True
    session["username"] = username
    session["mfa_completed"] = True
    return redirect(url_for("home"))

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("login"))

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""

    if not verify_password(username, password):
        return jsonify({"error": "Invalid username or password"}), 401

    token = issue_api_token(username)
    return jsonify({
        "message": "Login successful",
        "username": username,
        "mfa_skipped": True,
        "access_token": token,
        "token_type": "Bearer",
        "expires_in": 43200,
    })

@app.route("/api/me", methods=["GET"])
@api_token_required
def api_me():
    username = request.api_user
    user = USERS.get(username, {})
    return jsonify({
        "username": username,
        "mfa_enabled": user.get("mfa_enabled", False),
        "roles": user.get("roles", []),
    })

